INSERT INTO member_scheduled_posts (content, scheduled_for, status, metadata)
VALUES
  ('Every platform has a margin. Ours is locked — permanently — at Cost + 20%. Not "up to." Not "starting at." Exactly 20% over actual cost, written into the operating agreement. #LianaBanyan', current_date + interval '1 day' + interval '8 hours', 'draft', '{"campaign":"opening_gambit_salvo","stream":"platform-identity","day":1,"title":"Cost + 20%","target_platform":"twitter"}'::jsonb),
  ('On a $500 transaction, the creator keeps $416.67. 83.3%. Every time. Constitutionally locked. #LianaBanyan #CostPlus20', current_date + interval '2 days' + interval '8 hours', 'draft', '{"campaign":"opening_gambit_salvo","stream":"platform-identity","day":2,"title":"Creators Keep 83.3%","target_platform":"twitter"}'::jsonb),
  ('It costs $5 a year to join Liana Banyan. Start a business. Sell your work. Access 16 initiatives. Five dollars. lianabanyan.com/join #LianaBanyan', current_date + interval '3 days' + interval '8 hours', 'draft', '{"campaign":"opening_gambit_salvo","stream":"platform-identity","day":3,"title":"$5/Year Membership","target_platform":"twitter"}'::jsonb),
  ('Credits = spending money. Marks = earned contribution power. Joules = permanent record. None convert to cash. None can be speculated on. #LianaBanyan', current_date + interval '4 days' + interval '8 hours', 'draft', '{"campaign":"opening_gambit_salvo","stream":"platform-identity","day":4,"title":"Three Currencies","target_platform":"twitter"}'::jsonb),
  ('When you contribute to Liana Banyan, you become an owner. Not metaphorical. Real — with governance weight and a permanent on-chain record. #LianaBanyan', current_date + interval '5 days' + interval '8 hours', 'draft', '{"campaign":"opening_gambit_salvo","stream":"platform-identity","day":5,"title":"Cooperative Ownership","target_platform":"twitter"}'::jsonb),
  ('2,224 documented innovations. 202 survived with no prior art found — we call them Crown Jewels. Four decades of thinking. Nine years building. #LianaBanyan', current_date + interval '6 days' + interval '8 hours', 'draft', '{"campaign":"opening_gambit_salvo","stream":"platform-identity","day":6,"title":"2,224 Innovations","target_platform":"twitter"}'::jsonb),
  ('12 provisional patent applications. ~2,393 formal claims. 99% utility patents. We built the thing, then we protected it. #LianaBanyan', current_date + interval '7 days' + interval '8 hours', 'draft', '{"campaign":"opening_gambit_salvo","stream":"platform-identity","day":7,"title":"12 Provisional Patents","target_platform":"twitter"}'::jsonb),
  ('202 innovations with no prior art found across 130 deep-dive queries. 80% of the IP goes into the cooperative. #LianaBanyan', current_date + interval '8 days' + interval '8 hours', 'draft', '{"campaign":"opening_gambit_salvo","stream":"platform-identity","day":8,"title":"202 Crown Jewels","target_platform":"twitter"}'::jsonb),
  ('Zero venture capital. Zero investors. Funded by $5 memberships and the Founder''s savings. Because VC demands 10x extraction. #LianaBanyan', current_date + interval '9 days' + interval '8 hours', 'draft', '{"campaign":"opening_gambit_salvo","stream":"platform-identity","day":9,"title":"No VC","target_platform":"twitter"}'::jsonb),
  ('"Fair" means the same deal for everyone. $50 earrings and $5,000 furniture get the same 83.3%. Cost + 20%. Same architecture. #LianaBanyan', current_date + interval '10 days' + interval '8 hours', 'draft', '{"campaign":"opening_gambit_salvo","stream":"platform-identity","day":10,"title":"Fair Means Everyone","target_platform":"twitter"}'::jsonb),
  ('"Help Each Other Help Ourselves." Not independence — interdependence. I help you, you help them, they help us. HEOHO. #LianaBanyan', current_date + interval '11 days' + interval '8 hours', 'draft', '{"campaign":"opening_gambit_salvo","stream":"platform-identity","day":11,"title":"HEOHO","target_platform":"twitter"}'::jsonb),
  ('16 initiatives. One cooperative. Let''s Make Dinner. JukeBox. Health Accords. Defense Klaus. All funded by architecture, not pledges. #LianaBanyan', current_date + interval '12 days' + interval '8 hours', 'draft', '{"campaign":"opening_gambit_salvo","stream":"platform-identity","day":12,"title":"16 Initiatives","target_platform":"twitter"}'::jsonb),
  ('35 production systems. Not "planned." Built. Deployed. Running. We build. Then we ship. Then we build more. #LianaBanyan', current_date + interval '13 days' + interval '8 hours', 'draft', '{"campaign":"opening_gambit_salvo","stream":"platform-identity","day":13,"title":"35 Production Systems","target_platform":"twitter"}'::jsonb),
  ('6 cold start pathways: Founding 300, HexIsle, Crown Letters, Red Carpet, Academic circuit, Opening Gambit media salvo. You''re watching #6. #LianaBanyan', current_date + interval '14 days' + interval '8 hours', 'draft', '{"campaign":"opening_gambit_salvo","stream":"platform-identity","day":14,"title":"6 Cold Start Pathways","target_platform":"twitter"}'::jsonb);
INSERT INTO member_scheduled_posts (content, scheduled_for, status, metadata)
VALUES
  ('Platform cooperativism laid the groundwork. We built the architecture. Cost + 20%, locked. Creators keep 83.3%. 2,224 innovations. @TreborS #PlatformCooperativism', current_date + interval '1 day' + interval '13 hours', 'draft', '{"campaign":"opening_gambit_salvo","stream":"academic-tag","day":1,"title":"Trebor Scholz","target_platform":"twitter"}'::jsonb),
  ('Can cooperatives scale digitally? We built the answer. Three-gear currency. Medallion governance. 16 initiatives. @ntnsndr #PlatformCooperativism', current_date + interval '2 days' + interval '13 hours', 'draft', '{"campaign":"opening_gambit_salvo","stream":"academic-tag","day":2,"title":"Nathan Schneider","target_platform":"twitter"}'::jsonb),
  ('You coined "enshittification." We built the antidote. Margin locked in the operating agreement. Structurally impossible to enshittify. @doctorow', current_date + interval '3 days' + interval '13 hours', 'draft', '{"campaign":"opening_gambit_salvo","stream":"academic-tag","day":3,"title":"Cory Doctorow","target_platform":"twitter"}'::jsonb),
  ('Commons-based peer production meets cooperative commerce. The commons has an engine now. @ybenkler #CooperativeEconomics', current_date + interval '4 days' + interval '13 hours', 'draft', '{"campaign":"opening_gambit_salvo","stream":"academic-tag","day":4,"title":"Yochai Benkler","target_platform":"twitter"}'::jsonb),
  ('Doughnut Economics — what does a thriving economy look like? Cost + 20%. Creators keep 83.3%. The doughnut has a platform. @KateRaworth', current_date + interval '5 days' + interval '13 hours', 'draft', '{"campaign":"opening_gambit_salvo","stream":"academic-tag","day":5,"title":"Kate Raworth","target_platform":"twitter"}'::jsonb),
  ('Team Human has a marketplace now. No VC. No IPO pathway. The cooperative owns itself. @Rushkoff #TeamHuman', current_date + interval '6 days' + interval '13 hours', 'draft', '{"campaign":"opening_gambit_salvo","stream":"academic-tag","day":6,"title":"Douglas Rushkoff","target_platform":"twitter"}'::jsonb),
  ('Remove extraction architecturally and the surveillance business model collapses. The alternative is cooperative commerce. @ShoshanaZuboff', current_date + interval '7 days' + interval '13 hours', 'draft', '{"campaign":"opening_gambit_salvo","stream":"academic-tag","day":7,"title":"Shoshana Zuboff","target_platform":"twitter"}'::jsonb);
