INSERT INTO member_scheduled_posts (content, scheduled_for, status, metadata)
VALUES
  ('I''m a 53-year-old Army National Guard veteran. Father of eight. 21 years in IT. Nine years building Liana Banyan. Zero VC. Four AI agents. 2,224 innovations. $5/year to join. #CooperativeCommerce #VeteranEntrepreneur', current_date + interval '2 days' + interval '10 hours', 'draft', '{"campaign":"opening_gambit_salvo","stream":"linkedin-deep","day":2,"title":"The Founders Story","target_platform":"linkedin"}'::jsonb),
  ('Amazon charges 35%+. Etsy takes 30%. Uber takes 40%+. At Liana Banyan, the margin is locked at Cost + 20%. On $500: creator keeps $416.67. The math works because we have no investors demanding 10x returns. #CooperativeEconomics #CostPlus20', current_date + interval '5 days' + interval '10 hours', 'draft', '{"campaign":"opening_gambit_salvo","stream":"linkedin-deep","day":5,"title":"The Economics","target_platform":"linkedin"}'::jsonb),
  ('2,224 innovations. 12 provisional patents. ~2,393 formal claims. 202 Crown Jewels with no prior art. 80% of the IP goes into the cooperative. The IP fortress makes extraction impossible. #IntellectualProperty #Innovation', current_date + interval '8 days' + interval '10 hours', 'draft', '{"campaign":"opening_gambit_salvo","stream":"linkedin-deep","day":8,"title":"The IP Fortress","target_platform":"linkedin"}'::jsonb),
  ('The Opening Gambit: sacrifice material to gain position. 80% of the IP portfolio contributed to the cooperative. 300 founding memberships at $5/year. 500 members = break-even. 1,000 = profitable. lianabanyan.com/join #OpeningGambit #LianaBanyan', current_date + interval '11 days' + interval '10 hours', 'draft', '{"campaign":"opening_gambit_salvo","stream":"linkedin-deep","day":11,"title":"The Launch","target_platform":"linkedin"}'::jsonb);
